#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 3500
#define MAXM 1000000

int n, m;
int s, t;
int adj[MAX][MAX];
int dist[MAX];
int visited[MAX];

void bfs(int start) {
    int i, j;
    for (i = 0; i < n; i++) {
        dist[i] = -1;
        visited[i] = 0;
    }
    dist[start] = 0;
    visited[start] = 1;
    int queue[MAX];
    int front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        for (i = 0; i < n; i++) {
            if (adj[u][i] == 1 && !visited[i]) {
                dist[i] = dist[u] + 1;
                visited[i] = 1;
                queue[rear++] = i;
            }
        }
    }
}

int main() {
    scanf("%d %d", &n, &m);
    int i, j;
    for (i = 0; i < m; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--; v--;
        adj[u][v] = adj[v][u] = 1;
    }
    scanf("%d %d", &s, &t);
    s--; t--;
    bfs(s);
    printf("%d\n", dist[t] == -1 ? 0 : dist[t]);
    return 0;
}

