#include <iostream>
#include <queue>
#include <vector>
using namespace std;

const int MAX = 3500;
const int MAXM = 1000000;

int n, m;
int s, t;
vector<int> adj[MAX];
int dist[MAX];
bool visited[MAX];

void bfs(int start) {
    for (int i = 0; i < n; i++) {
        dist[i] = -1;
        visited[i] = false;
    }
    dist[start] = 0;
    visited[start] = true;
    queue<int> q;
    q.push(start);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int i = 0; i < adj[u].size(); i++) {
            int v = adj[u][i];
            if (!visited[v]) {
                dist[v] = dist[u] + 1;
                visited[v] = true;
                q.push(v);
            }
        }
    }
}

int main() {
    cin >> n >> m;
    for (int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        u--; v--;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    cin >> s >> t;
    s--; t--;
    bfs(s);
    cout << (dist[t] == -1 ? 0 : dist[t]) << endl;
    return 0;
}

