import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    static final int MAX = 3500;
    static final int MAXM = 1000000;
    static int n, m;
    static int s, t;
    static int[][] adj = new int[MAX][MAX];
    static int[] dist = new int[MAX];
    static boolean[] visited = new boolean[MAX];

    public static void bfs(int start) {
        for (int i = 0; i < n; i++) {
            dist[i] = -1;
            visited[i] = false;
        }
        dist[start] = 0;
        visited[start] = true;
        Queue<Integer> q = new LinkedList<>();
        q.add(start);
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int i = 0; i < n; i++) {
                if (adj[u][i] == 1 && !visited[i]) {
                    dist[i] = dist[u] + 1;
                    visited[i] = true;
                    q.add(i);
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        n = sc.nextInt();
        m = sc.nextInt();
        for (int i = 0; i < m; i++) {
            int u = sc.nextInt() - 1;
            int v = sc.nextInt() - 1;
            adj[u][v] = adj[v][u] = 1;
        }
        s = sc.nextInt() - 1;
        t = sc.nextInt() - 1;
        bfs(s);
        System.out.println(dist[t] == -1 ? 0 : dist[t]);
    }
}

